module RefModule(
    input clk,
    input rst,
    input ld,
    input [15:0] data,

    output reg [15:0] q
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk) begin
        if (rst) begin
            q <= 16'b0000000000000000;
        end else if (ld) begin
            q <= data;
        end
    end
endmodule
